sys_script_include.script:
var MediaUtils = Class.create();
MediaUtils.prototype = {
    initialize: function() {

    },

    refQualMedias: function() {
		var moviesToBeShown = [];
        var grMedias = new GlideRecord("x_153878_netflix_media");
        grMedias.addQuery("state", "3");
        grMedias.query();

        while (grMedias.next()){
            var grReview = new GlideRecord("x_153878_netflix_review");
			grReview.addQuery("opened_by", gs.getUserID());
			grReview.addQuery("media", grMedias.sys_id);
			grReview.addQuery("state", "!=", "4");
			grReview.query();
			if(!grReview.next()){
				moviesToBeShown.push(grMedias.getUniqueValue());
			}
        }
		return moviesToBeShown;
    },

    type: 'MediaUtils'
};
